import { EventStore, Event } from '../src/eventStore';

describe('EventStore', () => {
  let store: EventStore;

  beforeEach(() => {
    store = new EventStore();
  });

  test('appends events to a stream', () => {
    store.append('account-1', { type: 'Created', data: { name: 'Alice' } });
    store.append('account-1', { type: 'Deposited', data: { amount: 100 } });
    const events = store.getEvents('account-1');
    expect(events).toHaveLength(2);
    expect(events[0].type).toBe('Created');
    expect(events[1].type).toBe('Deposited');
  });

  test('events have auto-incremented version', () => {
    store.append('s1', { type: 'A', data: {} });
    store.append('s1', { type: 'B', data: {} });
    const events = store.getEvents('s1');
    expect(events[0].version).toBe(1);
    expect(events[1].version).toBe(2);
  });

  test('replays events to rebuild state', () => {
    store.append('cart-1', { type: 'ItemAdded', data: { item: 'apple', qty: 2 } });
    store.append('cart-1', { type: 'ItemAdded', data: { item: 'banana', qty: 1 } });
    store.append('cart-1', { type: 'ItemRemoved', data: { item: 'apple' } });

    const state = store.replay<Record<string, number>>('cart-1', {}, (state, event) => {
      if (event.type === 'ItemAdded') {
        return { ...state, [event.data.item]: (state[event.data.item] || 0) + event.data.qty };
      }
      if (event.type === 'ItemRemoved') {
        const { [event.data.item]: _, ...rest } = state;
        return rest;
      }
      return state;
    });

    expect(state).toEqual({ banana: 1 });
  });

  test('snapshot skips replaying old events', () => {
    store.append('acc-1', { type: 'Deposit', data: { amount: 100 } });
    store.append('acc-1', { type: 'Deposit', data: { amount: 50 } });
    store.saveSnapshot('acc-1', 2, { balance: 150 });
    store.append('acc-1', { type: 'Deposit', data: { amount: 25 } });

    let replayCount = 0;
    const state = store.replay<{ balance: number }>('acc-1', { balance: 0 }, (state, event) => {
      replayCount++;
      return { balance: state.balance + event.data.amount };
    });

    expect(state.balance).toBe(175);  // 150 from snapshot + 25 from new event
    expect(replayCount).toBe(1);  // only replayed 1 event after snapshot
  });

  test('streams are independent', () => {
    store.append('s1', { type: 'X', data: {} });
    store.append('s2', { type: 'Y', data: {} });
    expect(store.getEvents('s1')).toHaveLength(1);
    expect(store.getEvents('s2')).toHaveLength(1);
    expect(store.getEvents('s3')).toHaveLength(0);
  });
});

export interface Event {
  type: string;
  data: any;
  version?: number;
  timestamp?: Date;
}

interface StoredEvent extends Event {
  version: number;
  timestamp: Date;
}

interface Snapshot {
  version: number;
  state: any;
}

export class EventStore {
  private streams: Map<string, StoredEvent[]> = new Map();
  private snapshots: Map<string, Snapshot> = new Map();

  append(streamId: string, event: Event): StoredEvent {
    if (!this.streams.has(streamId)) {
      this.streams.set(streamId, []);
    }
    const events = this.streams.get(streamId)!;
    const stored: StoredEvent = {
      ...event,
      version: events.length + 1,
      timestamp: new Date(),
    };
    events.push(stored);
    return stored;
  }

  getEvents(streamId: string, afterVersion: number = 0): StoredEvent[] {
    const events = this.streams.get(streamId) || [];
    return events.filter(e => e.version > afterVersion);
  }

  replay<T>(streamId: string, initialState: T, reducer: (state: T, event: StoredEvent) => T): T {
    const snapshot = this.snapshots.get(streamId);
    let state = initialState;
    let fromVersion = 0;

    if (snapshot) {
      state = snapshot.state as T;
      fromVersion = snapshot.version;
    }

    const events = this.getEvents(streamId, fromVersion);
    for (const event of events) {
      state = reducer(state, event);
    }
    return state;
  }

  saveSnapshot(streamId: string, version: number, state: any): void {
    this.snapshots.set(streamId, { version, state });
  }
}
